// // This is a 2-bit synchronous counter with an enable signal and a synchronous reset.
// The counter decrements when enabled and resets to zero when reset is asserted.
module sync_counter (
    input clk,
    input reset,
    input enable,
    output reg [1:0] count);

always @(posedge clk) begin
    if (reset) begin
        count <= 2'b00;
    end else if (enable) begin
        count <= count + 1;
    end
end
endmodule
